const correction1ExpandedFiles = [
  "js/archive-actions.js","js/billing-calculation.js","js/billing-context.js","js/billing-workflow.js",
  "js/cost-actions.js","js/document-data.js","js/document-renderer.js","js/export-service.js",
  "js/master-data-actions.js","js/quality-rules.js","js/ui-billing-allocation.js","js/ui-master-data.js",
  "js/ui-quality.js","js/year-transition-actions.js","tests/ap22f8b-prepayments-browser.test.cjs",
  "tests/ap22f8b-prepayments.test.cjs","README.md","CHANGELOG.md","RELEASE_NOTES.md",
  "NK-PRO-PROJEKTSTAND.md","UI_MIGRATIONSMATRIX.md","UI_KOMPONENTENKATALOG.md","UI_UX_ABNAHMEKATALOG.md","SHA256SUMS.txt"
];
correction1ExpandedFiles.forEach(relative => delete protectedFiles[relative]);
const sha=data=>crypto.createHash("sha256").update(data).digest("hex");
for(const [relative,expected] of Object.entries(protectedFiles)){
  const target=path.join(root,relative);
  assert.ok(fs.existsSync(target),`Geschützte Datei fehlt: ${relative}`);
  const data=fs.readFileSync(target);
  assert.equal(data.length,expected.size,`Größe abweichend: ${relative}`);
  assert.equal(sha(data),expected.sha256,`Schutz-Hash abweichend: ${relative}`);
}
function sectionBounds(source,id){
  const marker=`id="${id}"`;
  const at=source.indexOf(marker); assert.notEqual(at,-1,`section#${id} fehlt`);
  const start=source.lastIndexOf("<section",at); assert.notEqual(start,-1);
  const rx=/<\/?section\b[^>]*>/ig; rx.lastIndex=start; let depth=0,match;
  while((match=rx.exec(source))){ depth+=match[0][1]==="/"?-1:1; if(depth===0)return {start,end:rx.lastIndex}; }
  throw new Error(`section#${id} unvollständig`);
}
const htmlBuffer=fs.readFileSync(path.join(root,"index.html"));
const html=htmlBuffer.toString("utf8");
const income=sectionBounds(html,"einnahmen");
const incomeStart=Buffer.byteLength(html.slice(0,income.start));
const incomeEnd=Buffer.byteLength(html.slice(0,income.end));
assert.equal(sha(htmlBuffer.subarray(0,incomeStart)),"c98367f53f368f79d9a5f964473ca2129045789d727936a88bc4f95a8d8c8ab2","index.html Präfix außerhalb section#einnahmen abweichend");
assert.equal(sha(htmlBuffer.subarray(incomeEnd+1)),"a22384237c1671236efffa3a9e7c94b5f7a73c4e5b73d1cf469fc1308b1b5728","index.html Suffix außerhalb section#einnahmen abweichend");
const css=fs.readFileSync(path.join(root,"assets/app.css"));
assert.equal(sha(css.subarray(0,313904)),"cfb0ed8e9248a0747ece6bede1bf4c8bf1535825f59d09d83b4568a59d34dcc3","assets/app.css geschützter Präfix abweichend");
const costs=fs.readFileSync(path.join(root,"js/ui-costs.js"));
const costStart=costs.indexOf(Buffer.from("const prepaymentUiState ="));
const costEnd=costs.indexOf(Buffer.from("function renderKosten()"));
assert.notEqual(costStart,-1,"AP22F8B UI-Hilfsbereich fehlt"); assert.notEqual(costEnd,-1,"renderKosten fehlt");
assert.equal(sha(costs.subarray(0,costStart)),"431739d47b23f979313ae04badd4486743982353af4309e0022b6ed43def13d4","js/ui-costs.js Präfix abweichend");
assert.equal(sha(costs.subarray(costEnd)),"f43efcc4bbba36c1e5534bb722204a457206c82ef5894dab57d0dc2c3cae7906","js/ui-costs.js Suffix abweichend");
const controller=fs.readFileSync(path.join(root,"js/ui-page-controller.js"));
const controllerStart=controller.indexOf(Buffer.from("  einnahmen:"));
const controllerEnd=controller.indexOf(Buffer.from("  wasser:"),controllerStart);
assert.equal(sha(controller.subarray(0,controllerStart)),"6a23a375d2500911e48e688bfc4afc3192f89412c57eef3d28c113e88c37e3b4","ui-page-controller Präfix abweichend");
assert.equal(sha(controller.subarray(controllerEnd)),"ab4c8233d0ed6a6bd3039b37384e4a52ac3c15f7b2b5a223bb851702723aa85d","ui-page-controller Suffix abweichend");
const bindings=fs.readFileSync(path.join(root,"js/ui-bindings.js"));
const bindingsStart=bindings.indexOf(Buffer.from('    registerController("cost"'));
const bindingsEnd=bindings.indexOf(Buffer.from('    registerController("billing"'),bindingsStart);
assert.equal(sha(bindings.subarray(0,bindingsStart)),"a4d41ee805e009895162b3d6b34298b2e451395f2f86ea7a22ba55e8ad9e84bd","ui-bindings Präfix abweichend");
assert.equal(sha(bindings.subarray(bindingsEnd)),"6ecc21ed0bb04c6e9b7246b461b286171e414ece31f18c8f0543e7de8f58ee6e","ui-bindings Suffix abweichend");
